async function loadResources(panel, ctx) {
  let data;
  try {
    data = await ctx.api.get('/api/learn/library/resources');
  } catch (err) {
    panel.innerHTML = `<p class="muted">Error loading resources: ${escapeHtml(String(err.message))}</p>`;
    return;
  }

  // Server returns flat [{path, filename, data}] — normalize to [{domain, resources:[...]}]
  const flat = Array.isArray(data) ? data : (data.groups || []);
  const byDomain = {};
  for (const item of flat) {
    const domain = item.data?.domain || item.domain || 'General';
    if (!byDomain[domain]) byDomain[domain] = [];
    byDomain[domain].push({
      title: item.data?.title || item.data?.resource_name || item.filename?.replace(/\.md$/, '') || 'Resource',
      url: item.data?.url || item.data?.link || '',
      description: item.data?.description || item.data?.summary || '',
    });
  }
  const groups = Object.entries(byDomain).map(([domain, resources]) => ({ domain, resources }));

  if (!groups.length) {
    panel.innerHTML = '<p class="muted">No resources found.</p>';

