async function handleResources(res, paths, domain) {
  const results = [];

  // 1. Scan 01_Domains/Deep_Dive_Resources — rich section-based resource packs
  try {
    const files = await readdir(paths.deepDiveResources, { withFileTypes: true });
    for (const f of files) {
      if (!f.isFile() || extname(f.name) !== '.md') continue;
      const filePath = join(paths.deepDiveResources, f.name);
      try {
        const raw = await readFile(filePath, 'utf8');
        const { data, content } = parseRawNote(raw);
        const title = data.title || f.name.replace(/\.md$/, '');
        if (domain && title.toLowerCase() !== domain.toLowerCase()) continue;
        const sections = parseResourceSections(content);
        results.push({ domain: title, sections, resources: sections.flatMap(s => s.items) });
      } catch { /* skip */ }
    }
  } catch { /* dir missing */ }

  // 2. Scan 09_Resources — simple captured/reference notes
  try {
    const files = await readdir(paths.resources, { withFileTypes: true });
    for (const f of files) {
      if (!f.isFile() || extname(f.name) !== '.md') continue;
      const filePath = join(paths.resources, f.name);
      try {
        const raw = await readFile(filePath, 'utf8');
        const { data } = parseRawNote(raw);
        if (domain && (data.domain || data.category || '').toLowerCase() !== domain.toLowerCase()) continue;
        results.push({
          domain: data.domain || data.category || 'Captured',
          resources: [{ title: data.name || data.title || f.name.replace(/\.md$/, ''), url: data.source_url || data.url || '', description: data.type || data.description || '' }],
        });
      } catch { /* skip */ }
    }
  } catch { /* dir missing */ }

  sendJson(res, results);
}

function parseResourceSections(content) {
  const sections = [];
  const lines = content.split('\n');
  let current = null;

  for (const line of lines) {
    const heading = line.match(/^## (.+)$/);
    if (heading) {
      if (current && current.items.length) sections.push(current);
      current = { heading: heading[1].trim(), items: [] };
      continue;
    }
    if (!current) continue;

    // Linked bullet: - [Title](url)
    const link = line.match(/^-\s+\[([^\]]+)\]\((https?:\/\/[^)]+)\)/);
    if (link) { current.items.push({ title: link[1].trim(), url: link[2].trim() }); continue; }

    // Non-linked bullet: - *Title* by Author  or  - plain text
    const bullet = line.match(/^-\s+(.+)$/);
    if (bullet) {
      const title = bullet[1].replace(/\*/g, '').trim();
      if (title) current.items.push({ title, url: '' });
    }
  }
  if (current && current.items.length) sections.push(current);
  return sections;
}

