async function loadResources(panel, ctx) {
  panel.innerHTML = `
    <div style="margin-bottom:1rem">
      <button id="res-capture-toggle" class="btn btn-sm btn-secondary">+ Capture URL</button>
      <div id="res-capture-form" style="display:none;margin-top:0.75rem" class="card">
        <div class="form-group">
          <label class="form-label" for="res-url-input">URL</label>
          <input id="res-url-input" class="form-input" type="url" placeholder="https://…" />
        </div>
        <div class="form-group">
          <label class="form-label" for="res-domain-input">Domain (optional)</label>
          <input id="res-domain-input" class="form-input" type="text" placeholder="e.g. Macro" />
        </div>
        <div id="res-capture-error" style="color:red;display:none;margin-bottom:0.5rem;font-size:0.85em"></div>
        <button id="res-capture-submit" class="btn btn-primary btn-sm">Capture</button>
      </div>
    </div>
    <div id="res-list"><p class="muted">Loading…</p></div>
  `;

  // Capture form toggle
  panel.querySelector('#res-capture-toggle').addEventListener('click', () => {
    const form = panel.querySelector('#res-capture-form');
    form.style.display = form.style.display === 'none' ? 'block' : 'none';
  });

  // Capture submit
  panel.querySelector('#res-capture-submit').addEventListener('click', async () => {
    const url = panel.querySelector('#res-url-input').value.trim();
    const domain = panel.querySelector('#res-domain-input').value.trim();
    const errEl = panel.querySelector('#res-capture-error');
    const btn = panel.querySelector('#res-capture-submit');
    if (!url) { errEl.textContent = 'URL is required.'; errEl.style.display = 'block'; return; }
    btn.disabled = true; btn.textContent = 'Capturing…'; errEl.style.display = 'none';
    try {
      await ctx.api.post('/api/learn/resource/capture', { url, domain });
      panel.querySelector('#res-capture-form').style.display = 'none';
      panel.querySelector('#res-url-input').value = '';
      await renderResourceList(panel.querySelector('#res-list'), ctx);
    } catch (err) {
      errEl.textContent = err.message; errEl.style.display = 'block';
    } finally {
      btn.disabled = false; btn.textContent = 'Capture';
    }
  });

  await renderResourceList(panel.querySelector('#res-list'), ctx);
}

