/**
 * learning-canvas.mjs — Auto-generate a JSON Canvas of the mastery node network.
 *
 * Usage:
 *   node run.mjs learn canvas
 *   node run.mjs learn canvas --all   (include locked + complete nodes)
 *
 * Output: 11_Learning/Node Map.canvas
 *
 * Layout:
 *   - Nodes arranged in a 4-column grid per domain group
 *   - Colored by stability: fragile=red(1), building=yellow(3), solid=green(4), mastered=blue(5)
 *   - Locked nodes are gray(6), complete nodes are purple(2)
 *   - Edges drawn from prerequisites:: inline field
 */

import { readdirSync, readFileSync, writeFileSync } from 'fs';
import { join, basename, extname } from 'path';
import { fileURLToPath } from 'url';
import { dirname } from 'path';

const __dirname = dirname(fileURLToPath(import.meta.url));
const VAULT_ROOT = join(__dirname, '..', '..');
const MASTERY_DIR = join(VAULT_ROOT, '11_Learning', '05_Mastery');
const OUTPUT = join(VAULT_ROOT, '11_Learning', 'Node Map.canvas');

const NODE_W = 340;
const NODE_H = 160;
const COL_GAP = 36;
const ROW_GAP = 36;
const COLS = 4;
const GROUP_PAD = 28;
const GROUP_HEADER = 56;
const GROUP_GAP = 56;

const STABILITY_COLOR = { fragile: '1', building: '3', solid: '4', mastered: '5' };
const STATE_COLOR = { active: null, complete: '2', locked: '6' };

/** Stable 16-char hex ID from a string (djb2 double hash) */
function stableId(str) {
  let h1 = 5381, h2 = 52711;
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    h1 = ((h1 << 5) + h1) ^ c;
    h2 = ((h2 << 5) + h2) ^ c;
  }
  const hex = (n) => (n >>> 0).toString(16).padStart(8, '0');
  return hex(h1) + hex(h2);
}

/** Extract inline field value: `key:: value` */
function inlineField(content, key) {
  const m = content.match(new RegExp(`^${key}::[ \\t]*(.*)$`, 'm'));
  return m ? m[1].trim() : '';
}

/** Extract YAML frontmatter value */
function fmValue(content, key) {
  const m = content.match(new RegExp(`^${key}:\\s*["']?([^"'\\n]+?)["']?\\s*$`, 'm'));
  return m ? m[1].trim() : '';
}

function loadMasteryNotes(includeAll) {
  const files = readdirSync(MASTERY_DIR).filter(f => extname(f) === '.md' && !f.startsWith('_'));
  return files.map(f => {
    const content = readFileSync(join(MASTERY_DIR, f), 'utf8');
    const topicId = inlineField(content, 'topic_id') || basename(f, '.md');
    return {
      file: basename(f, '.md'),
      topicId,
      domain: inlineField(content, 'domain') || 'General',
      level: Number(inlineField(content, 'level')) || 0,
      stability: inlineField(content, 'stability') || 'fragile',
      progressState: inlineField(content, 'progress_state') || 'active',
      prerequisites: inlineField(content, 'prerequisites') || 'none',
      nextAction: inlineField(content, 'next_action') || '',
    };
  }).filter(n => includeAll || n.progressState !== 'locked' || true); // show all by default
}

export async function run(flags = {}) {
  const includeAll = Boolean(flags.all);
  const notes = loadMasteryNotes(includeAll);

  if (!notes.length) {
    console.log('📭 No mastery notes found.');
    return;
  }

  // Group by domain
  const byDomain = {};
  for (const n of notes) {
    (byDomain[n.domain] = byDomain[n.domain] || []).push(n);
  }
  // Sort each domain group by level desc then name
  for (const group of Object.values(byDomain)) {
    group.sort((a, b) => b.level - a.level || a.topicId.localeCompare(b.topicId));
  }

  const nodes = [];
  const edges = [];
  const posMap = new Map(); // topicId → {x, y} for edge routing

  let cursorY = GROUP_PAD;

  for (const [domain, group] of Object.entries(byDomain)) {
    const rows = Math.ceil(group.length / COLS);
    const groupW = COLS * NODE_W + (COLS - 1) * COL_GAP + GROUP_PAD * 2;
    const groupH = GROUP_HEADER + rows * NODE_H + (rows - 1) * ROW_GAP + GROUP_PAD;
    const groupId = stableId(`group-${domain}`);

    nodes.push({
      id: groupId,
      type: 'group',
      x: 0,
      y: cursorY,
      width: groupW,
      height: groupH,
      label: domain,
    });

    group.forEach((n, i) => {
      const col = i % COLS;
      const row = Math.floor(i / COLS);
      const x = GROUP_PAD + col * (NODE_W + COL_GAP);
      const y = cursorY + GROUP_HEADER + row * (NODE_H + ROW_GAP);
      const nodeId = stableId(n.topicId);

      // Pick color: locked/complete override stability color
      const color = STATE_COLOR[n.progressState] ?? STABILITY_COLOR[n.stability] ?? '6';

      const stateLine = n.progressState === 'locked'
        ? '🔒 Locked'
        : `L${n.level} · ${n.stability}`;
      const text = `## ${n.topicId}\n\n**${stateLine}**\n\n[[11_Learning/05_Mastery/${n.file}]]`;

      nodes.push({ id: nodeId, type: 'text', x, y, width: NODE_W, height: NODE_H, color, text });
      posMap.set(n.topicId, { nodeId, cx: x + NODE_W / 2, cy: y + NODE_H / 2 });
    });

    cursorY += groupH + GROUP_GAP;
  }

  // Build edges from prerequisites
  const topicIds = new Set(notes.map(n => n.topicId));
  for (const n of notes) {
    const raw = n.prerequisites.trim();
    if (!raw || raw === 'none') continue;
    const prereqs = raw.split(',').map(s => s.trim().replace(/^\[\[|\]\]$/g, '').trim()).filter(Boolean);
    for (const prereq of prereqs) {
      if (!topicIds.has(prereq)) continue;
      const srcPos = posMap.get(prereq);
      const tgtPos = posMap.get(n.topicId);
      if (!srcPos || !tgtPos) continue;
      edges.push({
        id: stableId(`edge-${prereq}-${n.topicId}`),
        fromNode: srcPos.nodeId,
        toNode: tgtPos.nodeId,
        fromSide: 'bottom',
        toSide: 'top',
      });
    }
  }

  writeFileSync(OUTPUT, JSON.stringify({ nodes, edges }, null, 2), 'utf8');
  console.log(`🗺️  Node Map canvas written → 11_Learning/Node Map.canvas (${notes.length} nodes, ${edges.length} edges)`);
}

