  const { url, domain = 'General' } = body;
  if (!url) return sendError(res, 'url required', 400);

  // Try defuddle first (clean markdown), fall back to raw fetch
  let content = '';
  let usedDefuddle = false;
  const defuddleResult = spawnSync('defuddle', ['parse', url, '--md'], { encoding: 'utf8', timeout: 30000 });
  if (defuddleResult.status === 0 && defuddleResult.stdout?.trim().length > 100) {
    content = defuddleResult.stdout;
    usedDefuddle = true;
  } else {
    try {
      const fetchRes = await fetch(url, { headers: { 'User-Agent': 'vault-learn/1.0' } });
      if (!fetchRes.ok) throw new Error(`HTTP ${fetchRes.status}`);
