content.newText:
/**
 * thesis-canvas.mjs — Auto-generate a JSON Canvas of the thesis network.
 *
 * Usage:
 *   node run.mjs thesis canvas
 *
 * Output: 10_Theses/Thesis Map.canvas
 *
 * Layout:
 *   - Thesis nodes grouped by primary supporting regime (first entry in supporting_regimes)
 *   - Colored by conviction: high=green(4), medium=yellow(3), low=gray(6)
 *   - Edges drawn from each thesis to its secondary (non-primary) supporting regimes
 *   - Unclassified regime group catches any thesis with no supporting_regimes
 */

import { readdirSync, readFileSync, writeFileSync } from 'fs';
import { join, basename, extname } from 'path';
import { fileURLToPath } from 'url';
import { dirname } from 'path';

const __dirname = dirname(fileURLToPath(import.meta.url));
const VAULT_ROOT = join(__dirname, '..', '..');
const THESES_DIR = join(VAULT_ROOT, '10_Theses');
const OUTPUT = join(THESES_DIR, 'Thesis Map.canvas');

const NODE_W = 400;
const NODE_H = 200;
const COL_GAP = 40;
const ROW_GAP = 40;
const COLS = 3;
const GROUP_PAD = 32;
const GROUP_HEADER = 60;
const GROUP_GAP = 60;
const STANDALONE_W = 280;
const STANDALONE_H = 80;

const CONVICTION_COLOR = { high: '4', medium: '3', low: '6' };

/** Stable 16-char hex ID from a string (djb2 double hash) */
function stableId(str) {
  let h1 = 5381, h2 = 52711;
  for (let i = 0; i < str.length; i++) {
    const c = str.charCodeAt(i);
    h1 = ((h1 << 5) + h1) ^ c;
    h2 = ((h2 << 5) + h2) ^ c;
  }
  const hex = (n) => (n >>> 0).toString(16).padStart(8, '0');
  return hex(h1) + hex(h2);
}

/**
 * Parse YAML frontmatter into a flat key→value/array map.
 * Handles: scalar strings, inline arrays ["a","b"], and multi-line YAML arrays.
 */
function parseFrontmatter(content) {
  const m = content.match(/^---\r?\n([\s\S]*?)\r?\n---/);
  if (!m) return {};

  const fm = {};
  const lines = m[1].split('\n');
  let i = 0;

  while (i < lines.length) {
    const line = lines[i];

    // Inline array: key: ["item1", "item2"]
    const inlineArr = line.match(/^([\w]+):\s*\[(.*)\]\s*$/);
    if (inlineArr) {
      const raw = inlineArr[2].trim();
      fm[inlineArr[1]] = raw
        ? raw.split(',').map(s => s.trim().replace(/^["']|["']$/g, '').trim()).filter(Boolean)
        : [];
      i++;
      continue;
    }

    // Multi-line array: key:\n  - item
    const multiArr = line.match(/^([\w]+):\s*$/);
    if (multiArr && i + 1 < lines.length && lines[i + 1].match(/^\s+-\s/)) {
      const key = multiArr[1];
      const items = [];
      i++;
      while (i < lines.length && lines[i].match(/^\s+-\s/)) {
        items.push(lines[i].replace(/^\s+-\s*/, '').replace(/^["']|["']$/g, '').trim());
        i++;
      }
      fm[key] = items;
      continue;
    }

    // Scalar: key: value
    const scalar = line.match(/^([\w]+):\s*["']?(.+?)["']?\s*$/);
    if (scalar) {
      fm[scalar[1]] = scalar[2].trim();
    }
    i++;
  }
  return fm;
}

/** Strip [[ ]] wikilink brackets */
function stripWikilink(s) {
  return s.replace(/^\[\[|\]\]$/g, '').trim();
}

function loadTheses() {
  const files = readdirSync(THESES_DIR).filter(f => extname(f) === '.md' && !f.startsWith('_'));
  return files.map(f => {
    const content = readFileSync(join(THESES_DIR, f), 'utf8');
    const fm = parseFrontmatter(content);

    const regimes = Array.isArray(fm.supporting_regimes)
      ? fm.supporting_regimes.map(stripWikilink).filter(Boolean)
      : [];

    return {
      file: basename(f, '.md'),
      name: fm.name || basename(f, '.md'),
      conviction: (fm.conviction || 'medium').toLowerCase(),
      status: fm.status || 'Active',
      timeframe: fm.timeframe || '',
      regimes,
      primaryRegime: regimes[0] || 'Unclassified',
    };
  });
}

export async function run(_flags = {}) {
  const theses = loadTheses();

  if (!theses.length) {
    console.log('📭 No thesis notes found.');
    return;
  }

  // Group by primary regime, sort each group high→medium→low then alphabetical
  const byRegime = {};
  const convOrder = { high: 0, medium: 1, low: 2 };
  for (const t of theses) {
    (byRegime[t.primaryRegime] = byRegime[t.primaryRegime] || []).push(t);
  }
  for (const group of Object.values(byRegime)) {
    group.sort((a, b) =>
      (convOrder[a.conviction] ?? 1) - (convOrder[b.conviction] ?? 1) ||
      a.name.localeCompare(b.name)
    );
  }

  const nodes = [];
  const edges = [];
  const thesisNodeMap = new Map(); // thesis name → nodeId
  const regimeNodeMap = new Map(); // regime name → nodeId (group node for primaries)

  let cursorY = GROUP_PAD;

  // ── Primary regime groups + thesis nodes ─────────────────────────────────
  for (const [regime, group] of Object.entries(byRegime)) {
    const rows = Math.ceil(group.length / COLS);
    const groupW = COLS * NODE_W + (COLS - 1) * COL_GAP + GROUP_PAD * 2;
    const groupH = GROUP_HEADER + rows * NODE_H + (rows - 1) * ROW_GAP + GROUP_PAD;
    const groupId = stableId(`regime-group-${regime}`);

    nodes.push({
      id: groupId,
      type: 'group',
      x: 0,
      y: cursorY,
      width: groupW,
      height: groupH,
      label: regime,
    });
    regimeNodeMap.set(regime, groupId);

    group.forEach((t, i) => {
      const col = i % COLS;
      const row = Math.floor(i / COLS);
      const x = GROUP_PAD + col * (NODE_W + COL_GAP);
      const y = cursorY + GROUP_HEADER + row * (NODE_H + ROW_GAP);
      const nodeId = stableId(`thesis-${t.name}`);
      const color = CONVICTION_COLOR[t.conviction] ?? '6';

      const convLine = `${t.conviction.toUpperCase()} conviction · ${t.timeframe || 'unspecified'} horizon`;
      const text = `## ${t.name}\n\n**${convLine}**\n\n[[10_Theses/${t.file}]]`;

      nodes.push({ id: nodeId, type: 'text', x, y, width: NODE_W, height: NODE_H, color, text });
      thesisNodeMap.set(t.name, nodeId);
    });

    cursorY += groupH + GROUP_GAP;
  }

  // ── Standalone nodes for secondary regimes (not a primary of any thesis) ──
  const allSecondaryRegimes = new Set();
  for (const t of theses) {
    for (const r of t.regimes) {
      if (!regimeNodeMap.has(r)) allSecondaryRegimes.add(r);
    }
  }

  if (allSecondaryRegimes.size > 0) {
    let standaloneX = GROUP_PAD;
    for (const regime of allSecondaryRegimes) {
      const nodeId = stableId(`regime-node-${regime}`);
      nodes.push({
        id: nodeId,
        type: 'text',
        x: standaloneX,
        y: cursorY,
        width: STANDALONE_W,
        height: STANDALONE_H,
        color: '2',
        text: `**${regime}**`,
      });
      regimeNodeMap.set(regime, nodeId);
      standaloneX += STANDALONE_W + COL_GAP;
    }
  }

  // ── Edges: thesis → each secondary (non-primary) regime ──────────────────
  for (const t of theses) {
    const fromId = thesisNodeMap.get(t.name);
    if (!fromId) continue;
    for (const regime of t.regimes) {
      if (regime === t.primaryRegime) continue; // primary is implied by group membership
      const toId = regimeNodeMap.get(regime);
      if (!toId) continue;
      edges.push({
        id: stableId(`edge-thesis-regime-${t.name}-${regime}`),
        fromNode: fromId,
        toNode: toId,
        fromSide: 'bottom',
        toSide: 'top',
      });
    }
  }

  writeFileSync(OUTPUT, JSON.stringify({ nodes, edges }, null, 2), 'utf8');
  console.log(`🗺️  Thesis Map canvas written → 10_Theses/Thesis Map.canvas`);
  console.log(`   ${theses.length} theses · ${Object.keys(byRegime).length} regime groups · ${edges.length} cross-regime edges`);
}

