      monitor_status: fmValue(content, 'monitor_status'),
      allocation_priority: fmValue(content, 'allocation_priority'),
      supporting_regimes: fmArray(content, 'supporting_regimes'),
    };
  }).filter(t => includeAll || t.status === 'Active');
}

