  await ensureDir(paths.notebooks);
  const oldPath = join(paths.notebooks, `${slug}.md`);
  const newSlug = new_title.trim().toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '').replace(/\s+/g, '-').replace(/-+/g, '-');
  const newPath = join(paths.notebooks, `${newSlug}.md`);
  try {
    await fsRename(oldPath, newPath);
    sendJson(res, { success: true, new_slug: newSlug });
  } catch {
    sendError(res, `Notebook not found: ${slug}`, 404);
  }
}

async function handleAssignmentCreate(res, paths, body) {
  const { name, domain = '', description = '' } = body;
  if (!name?.trim()) return sendError(res, 'name required', 400);
  await ensureDir(paths.projects);
  const slug = name.trim().toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
  const filePath = join(paths.projects, `${slug}.md`);
  const content = [
    '---',
    `title: "${name.trim().replace(/"/g, "'")}"`,
    'project_status: queued',
    `domain: "${domain.replace(/"/g, "'")}"`,
    `created_date: ${todayStr()}`,
    'tags:',
    '  - project',
    '  - learning',
    '---',
    '',
    `# ${name.trim()}`,
    '',
    description || '',
    '',
  ].join('\n');
  await writeFile(filePath, content, 'utf8');
  sendJson(res, { success: true, id: slug, path: filePath });
}

async function handleAssignmentStatus(res, paths, id, body) {
  const { status } = body;
  const valid = ['queued', 'active', 'complete'];
  if (!valid.includes(status)) return sendError(res, `status must be one of: ${valid.join(', ')}`, 400);

  let files;
  try {
    files = await readdir(paths.projects, { withFileTypes: true });
  } catch {
    return sendError(res, 'Projects directory not found', 404);
  }

  for (const f of files) {
    if (!f.isFile() || extname(f.name) !== '.md') continue;
    const slug = f.name.replace(/\.md$/, '').toLowerCase().replace(/\s+/g, '-');
    if (slug !== id.toLowerCase()) continue;

    const filePath = join(paths.projects, f.name);
    let raw = await readFile(filePath, 'utf8');
    raw = raw.includes('project_status:')
      ? raw.replace(/^project_status:.*$/m, `project_status: ${status}`)
      : raw.replace(/^---\n/, `---\nproject_status: ${status}\n`);
    await writeFile(filePath, raw, 'utf8');
    return sendJson(res, { success: true, status });
  }
  sendError(res, `Assignment not found: ${id}`, 404);
}

async function handleWeeklyReview(res, paths) {
  try {
    const sessionMod = await import('../../learning-session.mjs');
    if (typeof sessionMod.buildWeeklyReviewNote !== 'function') {
      return sendError(res, 'buildWeeklyReviewNote not exported', 501);
    }
    const allNotes = await loadAllMastery(paths);
    const eventDomains = [...new Set(allNotes.map(n => n.inlineFields.domain).filter(Boolean))];
    const date = todayStr();
    const lines = sessionMod.buildWeeklyReviewNote({ date, projectPath: '', eventDomains });
    const content = Array.isArray(lines) ? lines.join('\n') : lines;
    await ensureDir(paths.reviews);
    const filePath = join(paths.reviews, `${date}-weekly.md`);
    await writeFile(filePath, content, 'utf8');
    sendJson(res, { success: true, date, path: filePath.replace(/\\/g, '/') });
  } catch (err) {
    sendError(res, `Failed to build weekly review: ${err.message}`, 500);
  }
}

