/** Render a 5-point pass/fail sparkline as inline SVG. */
function sparklineHTML(history) {
  const pts = Array.isArray(history) ? history.slice(-5) : [];
  const W = 58; const H = 18; const R = 3; const GAP = 12;
  const circles = Array.from({ length: 5 }, (_, i) => {
    const cx = 4 + i * GAP;
    const cy = H / 2;
    const val = pts[i - (5 - pts.length)];
    const fill = val === 'pass' ? '#4ade80' : val === 'fail' ? '#f87171' : '#444';
    return `<circle cx="${cx}" cy="${cy}" r="${R}" fill="${fill}" />`;
  }).join('');
  return `<svg width="${W}" height="${H}" style="display:block">${circles}</svg>`;
}

