/** Topics locked but whose prereqs are all at level ≥ 3 (nearly unlockable). */
function nearlyUnlockedHTML(masteryItems) {
  const byTopic = {};
  for (const m of masteryItems) {
    if (m.topic_id) byTopic[m.topic_id] = m;
  }

  const candidates = masteryItems.filter(m => {
    if (m.progress_state !== 'locked') return false;
    const prereqs = (m.prerequisites || '').trim();
    if (!prereqs || prereqs === 'none') return false;
    const prereqIds = prereqs.split(',').map(s => s.replace(/^\[\[|\]\]$/g, '').trim()).filter(Boolean);
    if (!prereqIds.length) return false;
    return prereqIds.every(pid => byTopic[pid] && (Number(byTopic[pid].level) || 0) >= 3);
  });

  if (!candidates.length) return '';

  const rows = candidates.map(m => `
    <tr>
      <td>${m.topic_id}</td>
      <td>${m.domain || '—'}</td>
      <td>${(m.prerequisites || '').replace(/^\[\[|\]\]$/g, '')}</td>
    </tr>`).join('');

  return `
    <div class="label" style="margin-bottom:10px;margin-top:20px;">&#128274; Nearly Unlocked</div>
    <div class="card" style="padding:0;overflow:hidden;">
      <table class="data-table">
        <thead><tr><th>Topic</th><th>Domain</th><th>Prerequisites Met</th></tr></thead>
        <tbody>${rows}</tbody>
      </table>
    </div>`;
}

